import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import Webcam from "react-webcam";
import axios from '../api/axios';

const StudyRoom = () => {
    const { id } = useParams(); // Task ID from URL
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    // State Management
    const [seconds, setSeconds] = useState(25 * 60); // 25 Minutes
    const [isActive, setIsActive] = useState(false);
    const [showExplanation, setShowExplanation] = useState(false);
    const [explanation, setExplanation] = useState("");

    // Automated Timer Flow
    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => {
                setSeconds((prev) => prev - 1);
            }, 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setIsActive(false);
            setShowExplanation(true); // Automatically switch UI when time is up
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinish = async () => {
        try {
            // Update status and save the explanation
            await axios.patch(`http://localhost:5000/api/tasks/${id}`, { 
                status: 'completed',
                userExplanation: explanation 
            });
            
            // Redirect to Plan Page
            navigate('/planPage');
        } catch (error) {
            console.error("Error finalizing day:", error);
        }
    };

    const formatTime = (secs) => {
        const mins = Math.floor(secs / 60);
        const s = secs % 60;
        return `${mins}:${s < 10 ? '0' : ''}${s}`;
    };

    return (
        <div className="study-container" style={{ padding: '40px', textAlign: 'center' }}>
            {!showExplanation ? (
                <>
                    <h2>Study Session Active</h2>
                    <div className="camera-wrapper" style={{ margin: '20px auto', width: '400px' }}>
                        <Webcam audio={false} ref={webcamRef} screenshotFormat="image/jpeg" width="100%" />
                    </div>
                    
                    <div style={{ fontSize: '4rem', margin: '20px', fontFamily: 'monospace' }}>
                        {formatTime(seconds)}
                    </div>

                    <button 
                        onClick={() => setIsActive(!isActive)}
                        style={{ padding: '10px 30px', fontSize: '1.2rem' }}
                    >
                        {isActive ? 'Pause Session' : 'Start Focus Timer'}
                    </button>
                </>
            ) : (
                <div className="explanation-section">
                    <h2>Time's Up!</h2>
                    <p>Briefly explain what you learned to complete Day 1:</p>
                    <textarea 
                        value={explanation}
                        onChange={(e) => setExplanation(e.target.value)}
                        placeholder="Write your summary here..."
                        style={{ width: '80%', height: '150px', padding: '15px', fontSize: '1rem' }}
                    />
                    <br />
                    <button 
                        onClick={handleFinish}
                        disabled={!explanation.trim()}
                        style={{ marginTop: '20px', padding: '10px 40px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '5px' }}
                    >
                        Finish & Update Status
                    </button>
                </div>
            )}
        </div>
    );
};

export default StudyRoom;
